//
import { mathAbs } from '../../../../core/zc-constants';
import { axis, legend } from '../../../../core/main-zc-init';
import { invokeFunction, simpleClone, bbox, getBoundingRect } from '../../../../utils/zcutils';
import { isSvgElement } from '../../../../utils/zcsvgutils';
import { updateChartAndPlotBound } from '../../../legend-bound';
import { getLegendArea } from '../../../legend-init';
import { expandableState } from '../../../expandable/expandable-parser';

function UpdateLegendAndPlot() {
    let manager = this,
        { chart, options } = manager,
        { legendInstance, markParser } = options,
        { element } = legendInstance;

    let expanded = expandableState(markParser),
        isSizeLegend = legendInstance.meta.encode === "z",
        allRendered = markParser.allRendered; // TODO: check

    if (allRendered || !expanded) {
        return;
    }

    let { isHorizontal } = markParser._spec, // TODO: work
        side = isHorizontal ? 'height' : 'width',
        isSVG = isSvgElement(element),
        oldBound = isSVG ? bbox(element) : getBoundingRect(element);

        let chartarea = simpleClone(chart.chartarea),
            plotarea = simpleClone(chart.plotarea);
        updateLegend(element, markParser, chart, isSizeLegend, oldBound, isSVG);

        let newBound = isSVG ? bbox(element) : getBoundingRect(element);

        if (mathAbs(newBound[side] - oldBound[side]) > 1) {
            let colorLegend = chart.legends.get('clr-0');
            chart.legendarea = getLegendArea(chart, colorLegend); // Adapting old method // TODO: Remove
            updatePlot(chart);
        } else {
            chart.chartarea = chartarea;
            chart.plotarea = plotarea;
            //chartarea and plotarea are reset in updateLegend, but only oif legend gets adjusted those values are recalculated above
            //in some cases above condition not satisfies and chartarea and plotarea remains improper(that is it got changed in updateLegend), so we changed it here.
        }

    markParser.allRendered = true;
}

function updateLegend(element, markParser, chart, isSizeLegend) {
    let { renderList, setLegendDimension, alignLegend } = markParser._spec;

    // if(isSizeLegend){
        element.styles({
            left: null,
            top: null
        });
    // }
    

    invokeFunction(renderList);
    invokeFunction(setLegendDimension);

    
    if (chart.legend.isSingleLayout) {
        invokeFunction(alignLegend, element, null,null,null,chart._chartarea);
    } else {
        chart.chartarea = simpleClone(chart._chartarea);
        chart.plotarea = simpleClone(chart._plotarea);
        legend.align(chart.legends, chart, chart.chartarea, chart.plotarea);
    }
}

function updatePlot(chart) {
    if (chart.legend.isSingleLayout) {
        chart.updatePlotArea();
        updateChartAndPlotBound(chart, true);
    }

    if (chart.isAxisCategory) {
        axis.render(chart, chart.chartWidth, chart.chartHeight, true);
    } else if (chart.dataObject.isPolarAxisCategory) {
        axis.polar.render(chart, 'x');
    }
    chart.drawThreshold(true);
    chart.drawPlotareaClippath();
    chart.updatePlotareaProp();
    chart.plot.renderer.draw(true);

    if (chart.isAxisCategory || chart.dataObject.isPolarAxisCategory) {
        chart.positionEventTrackerElement();
    }
}

export { UpdateLegendAndPlot };
